import {
    useEffect,
    useState
} from "react"

import {
    useParams,
    Link
} from "react-router-dom"

import Navbar from "../Navbar"

import BASE_URL from "../../services/api"

import "./index.css"

const ProposalDetails = () => {

    const { id } = useParams()

    const [proposal, setProposal] =
        useState(null)

    const [comments, setComments] =
        useState([])

    const [history, setHistory] =
        useState([])

    const [loading, setLoading] =
        useState(true)






    useEffect(() => {

        getProposalDetails()

    }, [])






    const getProposalDetails = async () => {

        try {

            const token =
                localStorage.getItem("token")






            const proposalResponse =
                await fetch(
                    `${BASE_URL}/events/${id}`,
                    {
                        headers: {
                            Authorization:
                            `Bearer ${token}`
                        }
                    }
                )

            const proposalData =
                await proposalResponse.json()






            const commentsResponse =
                await fetch(
                    `${BASE_URL}/events/${id}/comments`,
                    {
                        headers: {
                            Authorization:
                            `Bearer ${token}`
                        }
                    }
                )

            const commentsData =
                await commentsResponse.json()






            const historyResponse =
                await fetch(
                    `${BASE_URL}/events/${id}/history`,
                    {
                        headers: {
                            Authorization:
                            `Bearer ${token}`
                        }
                    }
                )

            const historyData =
                await historyResponse.json()






            setProposal(proposalData)

            setComments(commentsData)

            setHistory(historyData)

        } catch (error) {

            console.log(error)

        } finally {

            setLoading(false)
        }
    }






    const renderStatus = (status) => {

        if (status === "Approved") {

            return (
                <span className="approved">
                    Approved
                </span>
            )
        }

        if (status === "Rejected") {

            return (
                <span className="rejected">
                    Rejected
                </span>
            )
        }

        if (status === "In Review") {

            return (
                <span className="review">
                    In Review
                </span>
            )
        }

        if (
            status ===
            "Changes Required"
        ) {

            return (
                <span className="changes">
                    Changes Required
                </span>
            )
        }

        return (
            <span className="pending">
                Pending
            </span>
        )
    }






    if (loading) {

        return (
            <p className="loading-text">
                Loading...
            </p>
        )
    }






    if (!proposal) {

        return (
            <p className="loading-text">
                Proposal not found
            </p>
        )
    }






    return (

        <div className="details-bg">

            <Navbar />






            <div className="details-container">

                <div className="details-header">

                    <h1>
                        {proposal.title}
                    </h1>

                    {
                        renderStatus(
                            proposal.status
                        )
                    }

                </div>






                <div className="details-card">

                    <p>
                        <strong>
                            Category:
                        </strong>
                        {" "}
                        {proposal.category}
                    </p>

                    <p>
                        <strong>
                            Venue:
                        </strong>
                        {" "}
                        {proposal.venue}
                    </p>

                    <p>
                        <strong>
                            Proposed Date:
                        </strong>
                        {" "}
                        {proposal.proposed_date}
                    </p>

                    <p>
                        <strong>
                            Estimated Budget:
                        </strong>
                        {" "}
                        ₹
                        {proposal.estimated_budget}
                    </p>

                    <p>
                        <strong>
                            Expected Audience:
                        </strong>
                        {" "}
                        {proposal.expected_audience}
                    </p>

                    <p>
                        <strong>
                            Description:
                        </strong>
                    </p>

                    <p className="description">
                        {proposal.description}
                    </p>






                    {
                        proposal.document_link && (

                            <a
                                href={
                                    proposal.document_link
                                }
                                target="_blank"
                                rel="noreferrer"
                                className="doc-link"
                            >
                                View Document
                            </a>
                        )
                    }

                </div>






                {
                    proposal.status ===
                    "Pending" && (

                        <Link
                            to={`/edit-proposal/${proposal.id}`}
                            className="edit-btn"
                        >
                            Edit Proposal
                        </Link>
                    )
                }






                {/* COMMENTS */}

                <div className="section-box">

                    <h2>
                        Review Comments
                    </h2>






                    {
                        comments.length === 0
                        ? (
                            <p>
                                No comments yet
                            </p>
                        )
                        : (

                            comments.map(
                                each => (

                                    <div
                                        key={each.id}
                                        className="comment-card"
                                    >

                                        <div className="comment-top">

                                            <h4>
                                                {
                                                    each.reviewer_name
                                                }
                                            </h4>

                                            <span>
                                                {
                                                    each.reviewer_role
                                                }
                                            </span>

                                        </div>






                                        <p>
                                            {each.comment}
                                        </p>






                                        <small>
                                            {
                                                each.created_at
                                            }
                                        </small>

                                    </div>
                                )
                            )
                        )
                    }

                </div>






                {/* HISTORY */}

                <div className="section-box">

                    <h2>
                        Proposal Timeline
                    </h2>






                    {
                        history.map(
                            each => (

                                <div
                                    key={each.id}
                                    className="timeline-card"
                                >

                                    <h4>
                                        {each.action}
                                    </h4>

                                    <p>
                                        By:
                                        {" "}
                                        {
                                            each.performed_by_name
                                        }
                                    </p>

                                    <small>
                                        {
                                            each.created_at
                                        }
                                    </small>

                                </div>
                            )
                        )
                    }

                </div>

            </div>

        </div>
    )
}

export default ProposalDetails
